+        assert_eq!(a, c);
+        assert_ne!(ViolationSeverity::Warning, ViolationSeverity::Error);
+        assert_ne!(ViolationSeverity::Error, ViolationSeverity::Critical);
+        assert_ne!(ViolationSeverity::Warning, ViolationSeverity::Critical);
