+    #[test]
+    fn violation_clone_preserves_fields() {
+        let v = Violation {
+            kind: ViolationKind::SequenceGap,
+            severity: ViolationSeverity::Warning,
+            event_id: "evt-42".to_string(),
+            pane_id: 7,
+            message: "gap of 10".to_string(),
