+        };
+        let c = v.clone();
+        assert_eq!(c.kind, ViolationKind::SequenceGap);
+        assert_eq!(c.severity, ViolationSeverity::Warning);
+        assert_eq!(c.event_id, "evt-42");
+        assert_eq!(c.pane_id, 7);
+        assert_eq!(c.message, "gap of 10");
+        assert_eq!(c.event_index, 3);
+    }
