+    #[test]
+    fn invariant_report_has_errors_false_when_only_warnings() {
+        let report = InvariantReport {
+            violations: vec![
+                Violation {
+                    kind: ViolationKind::ClockRegression,
+                    severity: ViolationSeverity::Warning,
+                    event_id: "e1".into(),
+                    pane_id: 1,
+                    message: "warn".into(),
+                    event_index: 0,
+                },
+                Violation {
+                    kind: ViolationKind::SequenceGap,
+                    severity: ViolationSeverity::Warning,
+                    event_id: "e2".into(),
+                    pane_id: 1,
+                    message: "warn2".into(),
+                    event_index: 1,
+                },
+            ],
+            events_checked: 5,
+            panes_observed: 1,
+            domains_observed: 1,
